+              family inet {
+                  address 172.16.0.11/24;
+              }
+          }
+      }
+  }
+  policy-options {
+      policy-statement inet_to_blue {
+          term from_bgp {
+              from {
+                  instance master;
+                  protocol bgp;
+                  route-filter 10.20.0.0/24 orlonger;
+              }
+              then accept;
+          }
+          term reject {
+              then reject;
+          }
+      }
+      policy-statement send_direct {
+          term 1 {
+              from protocol direct;
+              then accept;
+          }
+          term reject {
+              then reject;
+          }
+      }
+  }
+  routing-options {
+      rib-groups {
+          blue_to_inet {
+              import-rib [ bluenet.inet.0 inet.0 ];
+          }
+          inet_to_blue {
+              import-rib [ inet.0 bluenet.inet.0 ];
+              import-policy inet_to_blue;
+          }
+      }
+  }
+  protocols {
+      bgp {
+          group overlay {
+              type internal;
+              local-address 172.16.0.11;
+              export send_direct;
+              local-as 64520;
+              neighbor 172.16.0.12 {
+                  peer-as 64520;
+              }
+          }
+      }
+  }

